pair A, B, C, D, M;

C = (0,0);
B = (Cos(13.1219),0);
A = (0,Sin(13.1210));
D = extension(A, incenter(A,B,C), B, C);
M = (B + C)/2;

draw(A--B--C--cycle);
draw(A--D);
