label("$A$",A,S);
label("$D$",D,S);
label("$C$",C,S);
label("$E$",E,S);
[/asy]

ref_solution:
Let $\theta = \angle DBA.$  Then $\angle CAB = \angle DBC = 2 \theta.$

[asy]
unitsize(3 cm);

pair A, B, C, D, O;

D = (0,0);
A = (1,0);
B = extension(D, D + dir(30), A, A + dir(45));
O = (B + D)/2;
C = 2*O - A;

draw(A--B--C--D--cycle);
draw(A--C);
draw(B--D);

